/* Human-readable label per type code, e.g. "2DL" -> "2 Dagdag Letra". */
export function typeLabel(type) {
  const m = /^(\d*)(DL|BL|KL|BS)$/.exec(type) || [];
  const n = m[1] || "";
  const names = {
    DL: "Dagdag Letra",
    BL: "Bawas Letra",
    KL: "Kislap Letra",
    BS: "Banat Salita"
  };
  const base = names[m[2]] || type;
  return n ? n + " " + base : base;
}
